-- 同步 D1 中過時的 pcb-defect-detection 內容（含失效的 quick-test.png 圖片路徑）
-- 改成新版 tiling 訓練法 + held-out 驗證的內容
UPDATE projects SET zh = '{"id": "pcb-defect-detection", "cover": "/images/pcb-defect-detection/cover.png", "category": "大學課程作品", "title": "PCB 線路瑕疵偵測：Azure Custom Vision 切塊物件偵測", "period": "2026", "description": "北大 PCB 瑕疵資料集，挑 3 個板型（01／04／05）× 3 種缺陷（missing_hole 缺孔、mouse_bite 鼠咬、open_circuit 斷路）訓練物件偵測。原圖是 3034×1586 的整板、缺陷框只有約 60px，直接丟 Custom Vision 會被縮到約 512px 而看不見，第一次訓練 mAP 只有 9.6%、Recall 3.1%。改成把大圖切成 600px 小塊再訓練後，mAP 拉到 81.9%、Precision 100%。匯出 TensorFlow model.pb，可在 Colab 載入推論。", "tags": ["Azure Custom Vision", "Object Detection", "影像切塊 Tiling", "model.pb · TensorFlow", "Pascal VOC"], "detail": {"images": [{"src": "/images/pcb-defect-detection/performance.png", "caption": "Advanced Training 成果：整體 Precision 100% / Recall 69.7% / mAP 81.9%（threshold 0.5），分缺陷數據見下方"}, {"src": "/images/pcb-defect-detection/dataset.png", "caption": "訓練資料：每張大圖以缺陷為中心切成 600px 塊，缺陷框佔比從約 2% 拉到約 12%（綠框為標註）"}, {"src": "/images/pcb-defect-detection/validation-zoom.png", "caption": "未參與訓練的板型 06／07 驗證（放大）：綠＝標註、紅＝模型預測，三類缺陷定位清楚"}, {"src": "/images/pcb-defect-detection/validation-board.png", "caption": "整板偵測：對 held-out 板做切塊推論後把框映射回原圖的完整結果"}, {"src": "/images/pcb-defect-detection/missing-hole/06_01.jpg", "caption": "missing_hole 偵測：板型 06 第 1 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/06_02.jpg", "caption": "missing_hole 偵測：板型 06 第 2 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/06_03.jpg", "caption": "missing_hole 偵測：板型 06 第 3 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/06_04.jpg", "caption": "missing_hole 偵測：板型 06 第 4 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/06_05.jpg", "caption": "missing_hole 偵測：板型 06 第 5 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/06_06.jpg", "caption": "missing_hole 偵測：板型 06 第 6 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/06_07.jpg", "caption": "missing_hole 偵測：板型 06 第 7 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/06_08.jpg", "caption": "missing_hole 偵測：板型 06 第 8 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/06_09.jpg", "caption": "missing_hole 偵測：板型 06 第 9 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/06_10.jpg", "caption": "missing_hole 偵測：板型 06 第 10 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/07_01.jpg", "caption": "missing_hole 偵測：板型 07 第 1 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/07_02.jpg", "caption": "missing_hole 偵測：板型 07 第 2 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/07_03.jpg", "caption": "missing_hole 偵測：板型 07 第 3 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/07_04.jpg", "caption": "missing_hole 偵測：板型 07 第 4 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/07_05.jpg", "caption": "missing_hole 偵測：板型 07 第 5 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/07_06.jpg", "caption": "missing_hole 偵測：板型 07 第 6 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/07_07.jpg", "caption": "missing_hole 偵測：板型 07 第 7 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/07_08.jpg", "caption": "missing_hole 偵測：板型 07 第 8 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/07_09.jpg", "caption": "missing_hole 偵測：板型 07 第 9 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/07_10.jpg", "caption": "missing_hole 偵測：板型 07 第 10 張（綠＝標註，紅＝模型預測）"}], "purpose": "作業要求：10 個板型裡至少挑 3 型、至少 3 種缺陷，用物件偵測訓練到 Precision 80% 以上，再對沒看過的板子做檢測，最後匯出 model.pb 能在 Colab 載入。\n\n真正卡住的不是訓練流程，是資料尺度。缺陷框只有約 60 像素，整張板卻是 3034×1586。Custom Vision 會把輸入縮到約 512px，縮完缺陷只剩約 10px，模型根本看不到——第一次照標準流程訓練，mAP 只有 9.6%、Recall 3.1%，等於沒用。", "concept": "【第一次失敗：直接上傳整圖】\n3 板型 × 3 缺陷共 150 張整圖連同 Pascal VOC 標註上傳，用 General (compact) domain 做 Advanced Training。結果 mAP 9.6%、Recall 3.1%——缺陷被縮圖吃掉了。\n\n【解法：影像切塊（tiling）】\n把每張大圖以缺陷框為中心切成 600×600 的小塊，框落在塊內超過 40% 面積才保留，座標重新換算成塊內的 0–1 正規化值。缺陷在塊裡的佔比從約 2% 拉到約 12%，縮到 512px 後仍有約 60px。3 缺陷共切出 438 塊重新訓練。\n\n【偵測也要切塊】\n推論時整板一樣會被縮小，所以對 PCB_USED 與驗證板也用同樣方式切塊逐塊偵測，把預測框映射回原圖座標，再用 IoU 0.3 的 NMS 去掉重疊塊造成的重複框。\n\n【匯出與 Colab】\n要能匯出 TensorFlow 一定得用 compact domain。匯出的模型輸出是 YOLO 風格原始張量（節點 model_outputs:0），解碼（anchors + NMS）沿用 Custom Vision 官方的 object_detection.py，沒有自己重寫。Colab 端把官方解碼器、model.pb、labels.txt 一起載入就能推論。", "outcome": "【Advanced Training 成果（threshold 0.5）】\nPrecision 100%　Recall 69.7%　mAP 81.9%\nmissing_hole　P 100%　R 100%　 AP 100%\nopen_circuit　P 100%　R 41.9%　AP 73.0%\nmouse_bite　　P 100%　R 64.7%　AP 72.8%\n\n切塊把 mAP 從 9.6% 拉到 81.9%，是這個專案最關鍵的一步。刻意用 Advanced Training 而不是 Quick Train。\n\n【拿沒訓練過的板型驗證（06、07）】\n訓練只用 01／04／05，驗證改用模型沒看過的 06、07 共 60 張缺陷圖：標準答案總共 303 個缺陷，模型輸出 306 個框，數量幾乎一比一。在沒看過的板型上仍抓得到缺陷，代表不是死背訓練資料。\n\n【誠實邊界：100% Precision 偏樂觀】\n這個 Precision 是 Custom Vision 用上傳影像做交叉驗證算的，而同一張板切出的塊背景幾乎一樣，相鄰塊可能一塊進訓練、一塊進驗證，數字會被高估。把模型實際用在 PCB_USED 那種原始、未標準化的實拍整板時，會冒出少量假陽性——這是訓練資料（乾淨、光照一致）和測試資料（斜拍、背景雜）不同調的 domain shift，不是傳統意義的過擬合。三類裡 mouse_bite 最弱（Recall 64.7%），鼠咬比缺孔細微、形狀也不規則，要往下做應該先補這類資料再重訓。", "tech": [{"group": "影像處理", "items": [{"name": "影像切塊 Tiling", "desc": "以缺陷框為中心切 600px 塊，框需 ≥40% 面積落在塊內才保留，座標換算回塊內 0–1；缺陷佔比從約 2% 提升到約 12%，是整個專案成敗的關鍵"}, {"name": "Pascal VOC 解析", "desc": "用 xml.etree.ElementTree 解析 bndbox，把像素座標換算成 Custom Vision 要求的 0–1 正規化座標"}]}, {"group": "雲端 AI 服務", "items": [{"name": "Azure Custom Vision SDK", "desc": "用 Python SDK 走完建專案（compact domain）、批次上傳含框影像、Advanced Training、發布、匯出 TensorFlow 的完整流程；刻意用 Advanced 而非 Quick Train"}, {"name": "model.pb 匯出與 Colab 載入", "desc": "匯出凍結圖 model.pb（輸入 Placeholder:0、輸出 model_outputs:0），在 Colab 以 tf.compat.v1 載入；YOLO 風格輸出的 anchors／NMS 解碼沿用官方 object_detection.py"}]}, {"group": "推論與驗證", "items": [{"name": "切塊推論 + NMS", "desc": "整板切塊逐塊偵測，預測框映射回原圖，再以 IoU 0.3 的 NMS 去除重疊塊造成的重複框"}, {"name": "Held-out 驗證", "desc": "用沒參與訓練的板型 06／07 做泛化測試，疊綠（標註）紅（預測）框輸出，直接看模型在新板上抓得準不準，而不是只信交叉驗證的數字"}]}], "github": ""}}', en = '{"id": "pcb-defect-detection", "cover": "/images/pcb-defect-detection/cover.png", "category": "University Coursework", "title": "PCB Trace Defect Detection: Tiled Object Detection with Azure Custom Vision", "period": "2026", "description": "Object detection on the Peking University PCB defect dataset, using 3 board types (01/04/05) and 3 defect classes (missing_hole, mouse_bite, open_circuit). The source images are full 3034×1586 boards where each defect box is only ~60px. Custom Vision shrinks input to ~512px, so defects vanished and the first training run reached only 9.6% mAP / 3.1% recall. After slicing each board into 600px tiles, mAP went up to 81.9% and precision to 100%. The TensorFlow model.pb is exported and loads in Colab.", "tags": ["Azure Custom Vision", "Object Detection", "Image Tiling", "model.pb · TensorFlow", "Pascal VOC"], "detail": {"images": [{"src": "/images/pcb-defect-detection/performance.png", "caption": "Advanced Training result: overall Precision 100% / Recall 69.7% / mAP 81.9% (threshold 0.5); per-class numbers below"}, {"src": "/images/pcb-defect-detection/dataset.png", "caption": "Training data: each board is sliced into 600px tiles centered on defects, raising defect-to-tile ratio from ~2% to ~12% (green = ground truth)"}, {"src": "/images/pcb-defect-detection/validation-zoom.png", "caption": "Held-out boards 06/07 (zoomed): green = ground truth, red = model prediction, across all three defect classes"}, {"src": "/images/pcb-defect-detection/validation-board.png", "caption": "Full-board detection: tiled inference on a held-out board with boxes mapped back to the original image"}, {"src": "/images/pcb-defect-detection/missing-hole/06_01.jpg", "caption": "missing_hole detection — board 06, #1 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/06_02.jpg", "caption": "missing_hole detection — board 06, #2 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/06_03.jpg", "caption": "missing_hole detection — board 06, #3 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/06_04.jpg", "caption": "missing_hole detection — board 06, #4 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/06_05.jpg", "caption": "missing_hole detection — board 06, #5 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/06_06.jpg", "caption": "missing_hole detection — board 06, #6 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/06_07.jpg", "caption": "missing_hole detection — board 06, #7 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/06_08.jpg", "caption": "missing_hole detection — board 06, #8 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/06_09.jpg", "caption": "missing_hole detection — board 06, #9 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/06_10.jpg", "caption": "missing_hole detection — board 06, #10 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/07_01.jpg", "caption": "missing_hole detection — board 07, #1 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/07_02.jpg", "caption": "missing_hole detection — board 07, #2 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/07_03.jpg", "caption": "missing_hole detection — board 07, #3 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/07_04.jpg", "caption": "missing_hole detection — board 07, #4 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/07_05.jpg", "caption": "missing_hole detection — board 07, #5 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/07_06.jpg", "caption": "missing_hole detection — board 07, #6 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/07_07.jpg", "caption": "missing_hole detection — board 07, #7 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/07_08.jpg", "caption": "missing_hole detection — board 07, #8 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/07_09.jpg", "caption": "missing_hole detection — board 07, #9 (green = ground truth, red = prediction)"}, {"src": "/images/pcb-defect-detection/missing-hole/07_10.jpg", "caption": "missing_hole detection — board 07, #10 (green = ground truth, red = prediction)"}], "purpose": "The assignment: from 10 board types, pick at least 3 types and at least 3 defect classes, train an object detector to 80%+ precision, run detection on unseen boards, and export a model.pb that loads in Colab.\n\nThe hard part wasn''t the training workflow, it was the scale of the data. Each defect box is about 60 pixels while the whole board is 3034×1586. Custom Vision shrinks input to about 512px, leaving defects at ~10px that the model simply can''t see. The first run by the standard workflow got 9.6% mAP and 3.1% recall, basically useless.", "concept": "[First attempt: upload full images]\n150 full images across 3 board types × 3 defects, with their Pascal VOC annotations, trained on the General (compact) domain with Advanced Training. Result: 9.6% mAP, 3.1% recall, the defects were lost to downscaling.\n\n[Fix: image tiling]\nSlice each board into 600×600 tiles centered on each defect box, keeping a box only if at least 40% of its area falls inside the tile, and re-normalizing coordinates to 0–1 within the tile. This raised the defect-to-tile ratio from ~2% to ~12%, so a defect is still ~60px after the 512px resize. The 3 defects produced 438 tiles for retraining.\n\n[Inference also needs tiling]\nA full board gets shrunk at inference too, so PCB_USED and the validation boards are sliced the same way and detected tile by tile, with predictions mapped back to original coordinates and duplicates from overlapping tiles removed by NMS at IoU 0.3.\n\n[Export and Colab]\nExporting TensorFlow requires a compact domain. The exported model outputs a YOLO-style raw tensor (node model_outputs:0); the anchor + NMS decoding reuses Custom Vision''s official object_detection.py rather than rewriting it. In Colab, loading that decoder together with model.pb and labels.txt is enough to run inference.", "outcome": "[Advanced Training result (threshold 0.5)]\nPrecision 100%　Recall 69.7%　mAP 81.9%\nmissing_hole　P 100%　R 100%　 AP 100%\nopen_circuit　P 100%　R 41.9%　AP 73.0%\nmouse_bite　　P 100%　R 64.7%　AP 72.8%\n\nTiling took mAP from 9.6% to 81.9%, the single step that made this project work. Advanced Training was used on purpose instead of Quick Train.\n\n[Validation on board types the model never saw (06, 07)]\nTraining used only 01/04/05. Validation used 60 defect images from board types 06 and 07: 303 ground-truth defects in total against 306 predicted boxes, almost one to one. Detecting defects on unseen board types means the model isn''t just memorizing the training data.\n\n[Honest limit: 100% precision is optimistic]\nThat precision comes from Custom Vision''s cross-validation over the uploaded images. Tiles from the same board share an almost identical background, so adjacent tiles can land one in training and one in validation, which inflates the number. Run on PCB_USED, the raw un-standardized photographed boards, the model produces a few false positives. That''s domain shift between clean, evenly-lit training data and angled, noisy test photos, not classic overfitting. Of the three classes mouse_bite is the weakest (64.7% recall); a mouse bite is subtler and more irregular than a missing hole, so the next step would be adding data for that class and retraining.", "tech": [{"group": "Image Processing", "items": [{"name": "Image Tiling", "desc": "Slice 600px tiles centered on each defect box, keep a box only if ≥40% of its area is inside the tile, re-normalize to 0–1; defect ratio rises from ~2% to ~12%, the make-or-break step of the project"}, {"name": "Pascal VOC Parsing", "desc": "Parse bndbox with xml.etree.ElementTree and convert pixel coordinates to the 0–1 normalized form Custom Vision requires"}]}, {"group": "Cloud AI Services", "items": [{"name": "Azure Custom Vision SDK", "desc": "Full flow via the Python SDK: create project (compact domain), batch-upload images with regions, Advanced Training, publish, export TensorFlow; Advanced was chosen over Quick Train on purpose"}, {"name": "model.pb Export and Colab Loading", "desc": "Export the frozen graph model.pb (input Placeholder:0, output model_outputs:0), load it in Colab with tf.compat.v1; the YOLO-style anchor/NMS decoding reuses the official object_detection.py"}]}, {"group": "Inference and Validation", "items": [{"name": "Tiled Inference + NMS", "desc": "Detect a full board tile by tile, map predictions back to the original image, then drop duplicate boxes from overlapping tiles with NMS at IoU 0.3"}, {"name": "Held-out Validation", "desc": "Generalization test on board types 06/07 that never appeared in training, drawing green (ground truth) and red (prediction) boxes to see how well the model locates defects on new boards rather than trusting the cross-validation numbers alone"}]}], "github": ""}}', updated_at = datetime("now") WHERE id = 'pcb-defect-detection';
